$$
\delta_{2}\left\langle\mathrm{u}_{\mathrm{k}}^{\mathrm{i}}\right\rangle=\sum_{\mathrm{l}=1}^{2} \sum_{\mathrm{j}=1}^{\mathrm{N}_{\mathrm{l}}} \mathrm{~J}_{\mathrm{kl}}^{\mathrm{ij}} \delta \mathrm{~m}_{\mathrm{l}}^{\mathrm{j}}
$$

$$
\left[\left(\delta\left\langle\mathrm{u}_{\mathrm{k}}^{\mathrm{i}}(\mathrm{t})\right\rangle\right)^{2}\right]=\sum_{\mathrm{l}=1}^{2} \mathrm{~J}_{\mathrm{kl}}^{2} q_{\mathrm{I}}=\mathrm{q}_{\mathrm{E}}+\mathrm{J}_{\mathrm{k}}^{2} \mathrm{q}_{\mathrm{I}}=\beta_{\mathrm{k}}
$$

from which one obtains

$$
\begin{aligned}
{\left[\left(u_{\mathrm{k}}^{\mathrm{i}}(\mathrm{t})-\left\langle u_{\mathrm{k}}^{\mathrm{i}}\right\rangle^{2}\right]\right.} & =\sum_{\mathrm{l}=1}^{2} \mathrm{~J}_{\mathrm{kl}}^{2}\left(\mathrm{~m}_{\mathrm{l}}-\mathrm{q}_{\mathrm{l}}\right)=\mathrm{m}_{\mathrm{E}}-\mathrm{q}_{\mathrm{E}}+\mathrm{J}_{\mathrm{k}}^{2}\left(\mathrm{~m}_{\mathrm{I}}-\mathrm{q}_{\mathrm{I}}\right) \\
& =\alpha_{\mathrm{k}}-\beta_{\mathrm{k}}
\end{aligned}
$$

$$
\mathrm{q}_{\mathrm{k}}=\int \mathrm{Dx}\left[\mathrm{H}\left(\frac{-\mathrm{u}_{\mathrm{k}}+\sqrt{\beta_{\mathrm{k}}} \mathrm{x}}{\sqrt{\alpha_{\mathrm{k}}-\beta_{\mathrm{k}}}}\right)\right]^{2}
$$

