\tau_{\mathrm{k}} \frac{\mathrm{dq}_{\mathrm{k}}(\tau)}{\mathrm{d} \tau}= & -\mathrm{q}_{\mathrm{k}}(\tau)+\int_{0}^{\infty} \frac{\mathrm{dt}}{\tau_{\mathrm{k}}} \\
& \times \exp \left(-\mathrm{t} / \tau_{\mathrm{k}}\right) \int \mathrm{Dx}\left[\mathrm{H}\left(\frac{-\mathrm{u}_{\mathrm{k}}-\sqrt{\beta_{\mathrm{k}}(\mathrm{t}+\tau)} \mathrm{x}}{\sqrt{\alpha_{\mathrm{k}}-\beta_{\mathrm{k}}(\mathrm{t}+\tau)}}\right)\right]^{2} .
\end{aligned}
$$

