\tau_{\mathrm{I}} \frac{\mathrm{dm}_{\mathrm{I}}^{1}}{\mathrm{dt}} & =\mathrm{J}_{\mathrm{IE}} \mathrm{~m}_{\mathrm{E}}^{1}+\left(\mathrm{JII}_{\mathrm{II}}-1\right) \mathrm{m}_{\mathrm{I}}^{1}-\tau_{\mathrm{I}} \mathrm{~A}_{\mathrm{I}} \frac{\mathrm{dm}_{0}}{\mathrm{dt}}
