$$

$$
\begin{aligned}
\mathrm{F}_{\mathrm{k}}= & \prod_{\mathrm{l}=1,2} \sum_{\mathrm{n}_{\mathrm{kl}}} \mathrm{p}_{\mathrm{l}}\left(\mathrm{n}_{1 \mathrm{l}}, \mathrm{n}_{2 \mathrm{l}}, \mathrm{n}_{3 \mathrm{l}}\right) \Theta\left(\sqrt{\mathrm{K}} \mathrm{~J}_{\mathrm{k} 0} \mathrm{~m}_{0}+\sum_{\mathrm{l}} \frac{\mathrm{~J}_{\mathrm{kl}}}{\sqrt{\mathrm{~K}}}\left(\mathrm{n}_{1 \mathrm{l}}+\mathrm{n}_{2 \mathrm{l}}\right)-\theta_{\mathrm{k}}\right) \\
& \times \Theta\left(\sqrt{\mathrm{K}} \mathrm{~J}_{\mathrm{k} 0} \mathrm{~m}_{0}+\sum_{\mathrm{l}} \frac{\mathrm{~J}_{\mathrm{kl}}}{\sqrt{\mathrm{~K}}}\left(\mathrm{n}_{1 \mathrm{l}}+\mathrm{n}_{3 \mathrm{l}}\right)-\theta_{\mathrm{k}}\right)
\end{aligned}
$$

In the large K limit, this can be written as

$$
\begin{aligned}
\mathrm{F}_{\mathrm{k}}= & \int \mathrm{D} \mathrm{x}_{1} \int \mathrm{D} \mathrm{x}_{2} \int \mathrm{D} \mathrm{x}_{3} \Theta\left(\mathrm{u}_{\mathrm{k}}+\sqrt{\beta_{\mathrm{k}}} \mathrm{x}_{1}+\sqrt{\alpha_{\mathrm{k}}-\beta_{\mathrm{k}}} \mathrm{x}_{2}-\theta_{\mathrm{k}}\right) \\
& \times \Theta\left(\mathrm{u}_{\mathrm{k}}+\sqrt{\beta_{\mathrm{k}}} \mathrm{x}_{1}+\sqrt{\alpha_{\mathrm{k}}-\beta_{\mathrm{k}}} \mathrm{x}_{3}-\theta_{\mathrm{k}}\right) \\
= & \int \mathrm{Dx}\left[\mathrm{H}\left(\frac{\theta_{\mathrm{k}}-\mathrm{u}_{\mathrm{k}}-\sqrt{\beta_{\mathrm{k}}} \mathrm{x}}{\sqrt{\alpha_{\mathrm{k}}-\beta_{\mathrm{k}}}}\right)\right]^{2}
\end{aligned}
$$

